# Upload local mirror to Drive (tarball+base64+extract).
import base64, tarfile, io
from pathlib import Path
PROJECT_ROOT = Path("/content/drive/MyDrive/diploma_plan_sql")
B64 = """"""
raw = base64.b64decode(B64)
print(f"got {len(raw)} bytes tarball")
with tarfile.open(fileobj=io.BytesIO(raw), mode="r:gz") as tar:
    tar.extractall(PROJECT_ROOT)
print("extracted to", PROJECT_ROOT)
# verify
import os
for sub in ["outputs","practice","repo","data"]:
    p = PROJECT_ROOT / sub
    n = sum(1 for _ in p.rglob("*") if _.is_file()) if p.exists() else 0
    print(f"  {sub}: {n} files")
print("STATUS=DONE")
